const W = 600; const H = 500;
const CID = 'pmap';

export default function ProvinceMap({ litProvinces }: ProvinceMapProps) {

  useEffect(() => {
    const t = setTimeout(() => {
      const ctx = Taro.createCanvasContext(CID);
      if (!ctx) return;

      ctx.setFillStyle('#F9F7F2');
      ctx.fillRect(0, 0, W, H);

      const names = Object.keys(P);
      names.forEach(name => {
        const s = P[name];
        const lit = litProvinces.has(name);
        const p = s.poly;
        ctx.beginPath();
        ctx.moveTo(p[0][0], p[0][1]);
        for (let i = 1; i < p.length; i++) ctx.lineTo(p[i][0], p[i][1]);
        ctx.closePath();
        if (lit) {
          ctx.setFillStyle('rgba(63,107,79,0.55)');
          ctx.fill();
          ctx.setStrokeStyle('#3F6B4F');
          ctx.setLineWidth(1.5);
        } else {
          ctx.setFillStyle('rgba(217,212,200,0.6)');
          ctx.fill();
          ctx.setStrokeStyle('rgba(139,130,110,0.18)');
          ctx.setLineWidth(0.8);
        }
        ctx.stroke();
      });

      // Labels
      names.forEach(name => {
        const s = P[name];
        ctx.setFillStyle(litProvinces.has(name) ? '#18231E' : '#A6AAA2');
        ctx.setFontSize(9);
        ctx.setTextAlign('center');
        ctx.fillText(name, s.cx, s.cy);
      });

      ctx.draw();
    }, 400);
    return () => clearTimeout(t);
  }, [litProvinces]);

  const handleTap = (e: any) => {
    const x = e?.detail?.x ?? 0; const y = e?.detail?.y ?? 0;
    let best = { name: '', dist: Infinity };
    Object.entries(P).forEach(([n, s]) => {
      const d = (x - s.cx) ** 2 + (y - s.cy) ** 2;
      if (d < best.dist) best = { name: n, dist: d };
    });
    if (best.dist < 2000) {
      const lit = litProvinces.has(best.name);
      Taro.showToast({ title: lit ? `已点亮${best.name}` : `还没有在${best.name}留下行者足迹`, icon: 'none' });
    }
  };

  return (
    <View style={{ width:'100%', background:'#FBFAF6', borderRadius:'28rpx', padding:'24rpx 16rpx 20rpx', border:'1rpx solid rgba(24,35,30,0.06)' }}>
      <View style={{ width:'100%', height:'420rpx', background:'#F9F7F2', borderRadius:'16rpx', overflow:'hidden' }}>
        <Canvas canvasId={CID} id={CID} style={{ width:'100%', height:'100%' }} onTouchEnd={handleTap} />
      </View>
      <View style={{ textAlign:'center', marginTop:'20rpx' }}>
        <Text style={{ fontSize:'24rpx', color:'#7A8178' }}>已点亮：</Text>
        {litProvinces.size === 0 ? (
          <Text style={{ fontSize:'24rpx', color:'#A6AAA2' }}>还没有点亮任何区域</Text>
        ) : (
          <Text style={{ fontSize:'26rpx', color:'#18231E' }}>{Array.from(litProvinces).join(' · ')}</Text>
        )}
      </View>
    </View>
  );
}
