/**
 * Build lit province set from certificate activity locations.
 */
export function getLitProvinces(certs: any[]): Set<string> {
  const lit = new Set<string>();
  certs.forEach((c: any) => {
    const loc = c.activity?.location || c.location;
    if (!loc) return;
    // Try exact match first
    if (CITY_TO_PROVINCE[loc]) { lit.add(CITY_TO_PROVINCE[loc]); return; }
    // Try fuzzy — if the location string contains a known city name
    for (const city of Object.keys(CITY_TO_PROVINCE)) {
      if (loc.includes(city)) { lit.add(CITY_TO_PROVINCE[city]); return; }
    }
  });
  return lit;
}
